#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, X;
        scanf("%d %d", &N, &X);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        int failed = 0, successful = 0;
        for (int i = 0; i < N; i++) {
            if (X >= A[i]) {
                X -= A[i];
                successful++;
            } else if (X < (A[i] + 1) / 2) {
                failed++;
            }
        }
        printf("%d %d\n", failed, successful);
    }
    return 0;
}

