import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int X = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            Arrays.sort(A);
            int failed = 0, successful = 0;
            for (int i = 0; i < N; i++) {
                if (X >= A[i]) {
                    X -= A[i];
                    successful++;
                } else if (X < (A[i] + 1) / 2) {
                    failed++;
                }
            }
            System.out.println(failed + " " + successful);
        }
    }
}

