const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, X] = readline().split(' ').map(Number);
    const A = readline().split(' ').map(Number).sort((a, b) => a - b);
    let failed = 0, successful = 0;
    for (let j = 0; j < N; j++) {
        if (X >= A[j]) {
            X -= A[j];
            successful++;
        } else if (X < Math.floor((A[j] + 1) / 2)) {
            failed++;
        }
    }
    console.log(failed + ' ' + successful);
}
